/* ═══════════════════════════════════════════════════════════════
   LandingPage.tsx
   ═══════════════════════════════════════════════════════════════ */
import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useProjects } from '../context/ProjectsContext';
import CloudmonSVG from '../components/CloudmonSVG';

const PHRASES = [
  'Visualize your architecture.',
  'See the impact of your design.',
  '1-click deploy on cloud or local.',
];

const TYPE_SPEED   = 48;   // ms per character typed
const DELETE_SPEED = 22;   // ms per character deleted
const HOLD_PAUSE   = 1800; // ms to hold the full phrase
const NEXT_PAUSE   = 320;  // ms pause before typing next phrase

function useTypewriter(phrases: string[]) {
  const [display, setDisplay]       = useState('');
  const [phraseIdx, setPhraseIdx]   = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const timeout = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const current = phrases[phraseIdx];

    if (!isDeleting && display === current) {
      // Fully typed – hold then start deleting
      timeout.current = setTimeout(() => setIsDeleting(true), HOLD_PAUSE);
    } else if (isDeleting && display === '') {
      // Fully deleted – move to next phrase
      setIsDeleting(false);
      timeout.current = setTimeout(
        () => setPhraseIdx((i) => (i + 1) % phrases.length),
        NEXT_PAUSE
      );
    } else {
      const next = isDeleting
        ? current.slice(0, display.length - 1)
        : current.slice(0, display.length + 1);
      timeout.current = setTimeout(
        () => setDisplay(next),
        isDeleting ? DELETE_SPEED : TYPE_SPEED
      );
    }

    return () => { if (timeout.current) clearTimeout(timeout.current); };
  }, [display, isDeleting, phraseIdx, phrases]);

  return display;
}

export default function LandingPage() {
  const navigate = useNavigate();
  const { createNewProject } = useProjects();
  const heroText = useTypewriter(PHRASES);

  function handleStart() {
    const project = createNewProject();
    navigate(`/projects/${project.id}`);
  }

  return (
    <div className="page landing">
      <div className="hero">
        <div className="hero-copy">
          <span className="hero-kicker">CloudMon</span>
          <h1 className="typewriter-h1">
            {heroText}<span className="typewriter-cursor" aria-hidden="true" />
          </h1>
          <h3>Considering dsitributing architecture?</h3>
          <h3>Considering using AWS EC2 instead of Azure VMs?</h3>
          <h3>Wondering how many users you can handle?</h3>
          <p>
            There have always been back-of-the-envolope estimations and intuitions that drive architecture design. 
            But now, you can actually visualize your architecture and estiamte the traffic it can handle, what bottlenecks you have, what the estimated cost might be.
          </p>
          <button className="btn-primary" onClick={handleStart}>
            Create a project
          </button>
        </div>
        <div className="panel-card">
          <CloudmonSVG />
        </div>
      </div>
    </div>

  );
}
